from __future__ import annotations

from dataclasses import asdict, dataclass, field, is_dataclass
import hashlib
import json
from typing import Any, Dict, List, Mapping, Optional


class OpportunityCandidateError(RuntimeError):
    """Raised when scanner/discovery opportunity candidate inputs are invalid."""


def _require_non_empty_string(name: str, value: Any) -> str:
    if not isinstance(value, str) or not value.strip():
        raise OpportunityCandidateError(f"{name} must be a non-empty string")
    return value.strip()


def _normalize_non_negative_float(name: str, value: Any) -> float:
    if isinstance(value, bool):
        raise OpportunityCandidateError(f"{name} must be a non-negative number")
    if isinstance(value, str):
        try:
            value = float(value.strip())
        except ValueError as exc:
            raise OpportunityCandidateError(f"{name} must be a non-negative number") from exc
    if not isinstance(value, (int, float)):
        raise OpportunityCandidateError(f"{name} must be a non-negative number")
    normalized = float(value)
    if normalized < 0.0:
        raise OpportunityCandidateError(f"{name} must be a non-negative number")
    return normalized


def _normalize_optional_float(name: str, value: Any) -> Optional[float]:
    if value is None:
        return None
    return _normalize_non_negative_float(name, value)


def _normalize_metadata(value: Any) -> Dict[str, Any]:
    if value is None:
        return {}
    if not isinstance(value, Mapping):
        raise OpportunityCandidateError("metadata must be a mapping when provided")
    return dict(value)


def _normalize_string_list(name: str, value: Any) -> List[str]:
    if value is None:
        return []
    if not isinstance(value, list):
        raise OpportunityCandidateError(f"{name} must be a list when provided")
    return [_require_non_empty_string(f"{name}[]", item) for item in value]


def _stable_id(prefix: str, payload: Mapping[str, Any]) -> str:
    digest = hashlib.sha256(
        json.dumps(dict(payload), sort_keys=True, default=str).encode("utf-8")
    ).hexdigest()[:16]
    return f"{prefix}_{digest}"


def _mapping_from_value(name: str, value: Any) -> Dict[str, Any]:
    if value is None:
        raise OpportunityCandidateError(f"{name} is required")

    if isinstance(value, Mapping):
        return dict(value)

    to_dict = getattr(value, "to_dict", None)
    if callable(to_dict):
        payload = to_dict()
        if not isinstance(payload, Mapping):
            raise OpportunityCandidateError(f"{name}.to_dict() must return a mapping")
        return dict(payload)

    if is_dataclass(value) and not isinstance(value, type):
        payload = asdict(value)
        if not isinstance(payload, dict):
            raise OpportunityCandidateError(f"{name} dataclass did not normalize to a dict")
        return payload

    if hasattr(value, "__dict__"):
        return {key: item for key, item in vars(value).items() if not key.startswith("_")}

    raise OpportunityCandidateError(f"{name} must be mapping-like or expose to_dict()")


@dataclass(frozen=True)
class OpportunityCandidateLineage:
    scanner_run_id: str
    discovery_source_id: str
    source_family: str
    source_opportunity_id: Optional[str] = None
    strategy_hint_id: Optional[str] = None
    metadata: Dict[str, Any] = field(default_factory=dict)
    opportunity_candidate_lineage_id: str = field(init=False)

    def __post_init__(self) -> None:
        scanner_run_id = _require_non_empty_string("scanner_run_id", self.scanner_run_id)
        discovery_source_id = _require_non_empty_string(
            "discovery_source_id",
            self.discovery_source_id,
        )
        source_family = _require_non_empty_string("source_family", self.source_family).lower()
        source_opportunity_id = (
            None if self.source_opportunity_id is None
            else _require_non_empty_string("source_opportunity_id", self.source_opportunity_id)
        )
        strategy_hint_id = (
            None if self.strategy_hint_id is None
            else _require_non_empty_string("strategy_hint_id", self.strategy_hint_id)
        )
        metadata = _normalize_metadata(self.metadata)

        object.__setattr__(self, "scanner_run_id", scanner_run_id)
        object.__setattr__(self, "discovery_source_id", discovery_source_id)
        object.__setattr__(self, "source_family", source_family)
        object.__setattr__(self, "source_opportunity_id", source_opportunity_id)
        object.__setattr__(self, "strategy_hint_id", strategy_hint_id)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(
            self,
            "opportunity_candidate_lineage_id",
            _stable_id(
                "opportunity_candidate_lineage",
                {
                    "scanner_run_id": scanner_run_id,
                    "discovery_source_id": discovery_source_id,
                    "source_family": source_family,
                    "source_opportunity_id": source_opportunity_id,
                    "strategy_hint_id": strategy_hint_id,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "scanner_run_id": self.scanner_run_id,
            "discovery_source_id": self.discovery_source_id,
            "source_family": self.source_family,
            "source_opportunity_id": self.source_opportunity_id,
            "strategy_hint_id": self.strategy_hint_id,
            "metadata": dict(self.metadata),
            "opportunity_candidate_lineage_id": self.opportunity_candidate_lineage_id,
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "OpportunityCandidateLineage":
        if not isinstance(payload, Mapping):
            raise OpportunityCandidateError("lineage payload must be a mapping")
        return cls(
            scanner_run_id=payload.get("scanner_run_id"),
            discovery_source_id=payload.get("discovery_source_id"),
            source_family=payload.get("source_family"),
            source_opportunity_id=payload.get("source_opportunity_id"),
            strategy_hint_id=payload.get("strategy_hint_id"),
            metadata=dict(payload.get("metadata") or {}),
        )


@dataclass(frozen=True)
class OpportunityFeatureInputs:
    route_score: float
    liquidity_score: float
    freshness_score: float
    latency_ms: float
    expected_edge_bps: float
    market_structure_score: Optional[float] = None
    spread_bps: Optional[float] = None
    metadata: Dict[str, Any] = field(default_factory=dict)
    opportunity_feature_inputs_id: str = field(init=False)

    def __post_init__(self) -> None:
        route_score = _normalize_non_negative_float("route_score", self.route_score)
        liquidity_score = _normalize_non_negative_float("liquidity_score", self.liquidity_score)
        freshness_score = _normalize_non_negative_float("freshness_score", self.freshness_score)
        latency_ms = _normalize_non_negative_float("latency_ms", self.latency_ms)
        expected_edge_bps = _normalize_non_negative_float(
            "expected_edge_bps",
            self.expected_edge_bps,
        )
        market_structure_score = _normalize_optional_float(
            "market_structure_score",
            self.market_structure_score,
        )
        spread_bps = _normalize_optional_float("spread_bps", self.spread_bps)
        metadata = _normalize_metadata(self.metadata)

        object.__setattr__(self, "route_score", route_score)
        object.__setattr__(self, "liquidity_score", liquidity_score)
        object.__setattr__(self, "freshness_score", freshness_score)
        object.__setattr__(self, "latency_ms", latency_ms)
        object.__setattr__(self, "expected_edge_bps", expected_edge_bps)
        object.__setattr__(self, "market_structure_score", market_structure_score)
        object.__setattr__(self, "spread_bps", spread_bps)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(
            self,
            "opportunity_feature_inputs_id",
            _stable_id(
                "opportunity_feature_inputs",
                {
                    "route_score": route_score,
                    "liquidity_score": liquidity_score,
                    "freshness_score": freshness_score,
                    "latency_ms": latency_ms,
                    "expected_edge_bps": expected_edge_bps,
                    "market_structure_score": market_structure_score,
                    "spread_bps": spread_bps,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "route_score": self.route_score,
            "liquidity_score": self.liquidity_score,
            "freshness_score": self.freshness_score,
            "latency_ms": self.latency_ms,
            "expected_edge_bps": self.expected_edge_bps,
            "market_structure_score": self.market_structure_score,
            "spread_bps": self.spread_bps,
            "metadata": dict(self.metadata),
            "opportunity_feature_inputs_id": self.opportunity_feature_inputs_id,
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "OpportunityFeatureInputs":
        if not isinstance(payload, Mapping):
            raise OpportunityCandidateError("feature_inputs payload must be a mapping")
        return cls(
            route_score=payload.get("route_score"),
            liquidity_score=payload.get("liquidity_score"),
            freshness_score=payload.get("freshness_score"),
            latency_ms=payload.get("latency_ms"),
            expected_edge_bps=payload.get("expected_edge_bps"),
            market_structure_score=payload.get("market_structure_score"),
            spread_bps=payload.get("spread_bps"),
            metadata=dict(payload.get("metadata") or {}),
        )


@dataclass(frozen=True)
class OpportunityCandidate:
    chain: str
    venue: str
    instrument: str
    symbol: str
    pair: str
    side: str
    opportunity_kind: str
    observed_at_utc: str
    freshness_bucket: str
    lineage: OpportunityCandidateLineage
    feature_inputs: OpportunityFeatureInputs
    tags: List[str] = field(default_factory=list)
    metadata: Dict[str, Any] = field(default_factory=dict)
    opportunity_candidate_id: str = field(init=False)

    def __post_init__(self) -> None:
        chain = _require_non_empty_string("chain", self.chain).lower()
        venue = _require_non_empty_string("venue", self.venue).lower()
        instrument = _require_non_empty_string("instrument", self.instrument).upper()
        symbol = _require_non_empty_string("symbol", self.symbol).upper()
        pair = _require_non_empty_string("pair", self.pair).upper()
        side = _require_non_empty_string("side", self.side).upper()
        if side not in {"LONG", "SHORT", "BUY", "SELL"}:
            raise OpportunityCandidateError("side must be LONG, SHORT, BUY, or SELL")

        opportunity_kind = _require_non_empty_string(
            "opportunity_kind",
            self.opportunity_kind,
        ).lower()
        if opportunity_kind not in {"spot", "perp", "arb", "swing", "momentum"}:
            raise OpportunityCandidateError(
                "opportunity_kind must be one of: spot, perp, arb, swing, momentum"
            )

        observed_at_utc = _require_non_empty_string("observed_at_utc", self.observed_at_utc)
        freshness_bucket = _require_non_empty_string(
            "freshness_bucket",
            self.freshness_bucket,
        ).lower()
        if freshness_bucket not in {"fresh", "warm", "stale"}:
            raise OpportunityCandidateError("freshness_bucket must be fresh, warm, or stale")

        lineage = (
            self.lineage
            if isinstance(self.lineage, OpportunityCandidateLineage)
            else OpportunityCandidateLineage.from_dict(_mapping_from_value("lineage", self.lineage))
        )
        feature_inputs = (
            self.feature_inputs
            if isinstance(self.feature_inputs, OpportunityFeatureInputs)
            else OpportunityFeatureInputs.from_dict(
                _mapping_from_value("feature_inputs", self.feature_inputs)
            )
        )
        tags = _normalize_string_list("tags", self.tags)
        metadata = _normalize_metadata(self.metadata)

        object.__setattr__(self, "chain", chain)
        object.__setattr__(self, "venue", venue)
        object.__setattr__(self, "instrument", instrument)
        object.__setattr__(self, "symbol", symbol)
        object.__setattr__(self, "pair", pair)
        object.__setattr__(self, "side", side)
        object.__setattr__(self, "opportunity_kind", opportunity_kind)
        object.__setattr__(self, "observed_at_utc", observed_at_utc)
        object.__setattr__(self, "freshness_bucket", freshness_bucket)
        object.__setattr__(self, "lineage", lineage)
        object.__setattr__(self, "feature_inputs", feature_inputs)
        object.__setattr__(self, "tags", tags)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(
            self,
            "opportunity_candidate_id",
            _stable_id(
                "opportunity_candidate",
                {
                    "chain": chain,
                    "venue": venue,
                    "instrument": instrument,
                    "symbol": symbol,
                    "pair": pair,
                    "side": side,
                    "opportunity_kind": opportunity_kind,
                    "observed_at_utc": observed_at_utc,
                    "freshness_bucket": freshness_bucket,
                    "lineage_id": lineage.opportunity_candidate_lineage_id,
                    "feature_inputs_id": feature_inputs.opportunity_feature_inputs_id,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "chain": self.chain,
            "venue": self.venue,
            "instrument": self.instrument,
            "symbol": self.symbol,
            "pair": self.pair,
            "side": self.side,
            "opportunity_kind": self.opportunity_kind,
            "observed_at_utc": self.observed_at_utc,
            "freshness_bucket": self.freshness_bucket,
            "lineage": self.lineage.to_dict(),
            "feature_inputs": self.feature_inputs.to_dict(),
            "tags": list(self.tags),
            "metadata": dict(self.metadata),
            "opportunity_candidate_id": self.opportunity_candidate_id,
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "OpportunityCandidate":
        if not isinstance(payload, Mapping):
            raise OpportunityCandidateError("candidate payload must be a mapping")
        return cls(
            chain=payload.get("chain"),
            venue=payload.get("venue"),
            instrument=payload.get("instrument"),
            symbol=payload.get("symbol"),
            pair=payload.get("pair"),
            side=payload.get("side"),
            opportunity_kind=payload.get("opportunity_kind"),
            observed_at_utc=payload.get("observed_at_utc"),
            freshness_bucket=payload.get("freshness_bucket"),
            lineage=payload.get("lineage"),
            feature_inputs=payload.get("feature_inputs"),
            tags=list(payload.get("tags") or []),
            metadata=dict(payload.get("metadata") or {}),
        )


def normalize_opportunity_candidate(value: Any) -> OpportunityCandidate:
    if isinstance(value, OpportunityCandidate):
        return value
    return OpportunityCandidate.from_dict(_mapping_from_value("opportunity_candidate", value))
